import * as React from 'react'

import { cn } from '@/lib/utils'

function Card({ className, ...props }: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="card"
      className={cn(
        'bg-background text-card-foreground flex flex-col gap-4 rounded-xl border border-border/50 py-4',
        className,
      )}
      {...props}
    />
  )
}

function CardHeader({ className, ...props }: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="card-header"
      className={cn(
        '@container/card-header grid auto-rows-min grid-rows-[auto_auto] items-start gap-1.5 px-4 has-data-[slot=card-action]:grid-cols-[1fr_auto] [.border-b]:pb-4',
        className,
      )}
      {...props}
    />
  )
}

function CardTitle({ className, ...props }: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="card-title"
      className={cn('leading-none font-semibold', className)}
      {...props}
    />
  )
}

function CardDescription({ className, ...props }: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="card-description"
      className={cn('text-muted-foreground text-sm', className)}
      {...props}
    />
  )
}

function CardAction({ className, ...props }: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="card-action"
      className={cn(
        'col-start-2 row-span-2 row-start-1 self-start justify-self-end',
        className,
      )}
      {...props}
    />
  )
}

function CardContent({ className, ...props }: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="card-content"
      className={cn('px-4', className)}
      {...props}
    />
  )
}

function CardFooter({ className, ...props }: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="card-footer"
      className={cn('flex items-center px-4 [.border-t]:pt-4', className)}
      {...props}
    />
  )
}

export {
  Card,
  CardHeader,
  CardFooter,
  CardTitle,
  CardAction,
  CardDescription,
  CardContent,
}

"use client"

import { useState } from "react"
import { Download, Loader2, FileText } from "lucide-react"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"
import type { ProposalSection, ProposalModelo } from "@/lib/proposal-types"
import { formatDateShort } from "@/lib/proposal-types"
import { generateWaProjectProposalPDF } from "@/lib/wa-project-pdf-generator"

interface ProposalTemplateWaProps {
  empresa: string
  para?: string
  projeto?: string
  proposalNumber: string
  dataCriacao: number
  sections: ProposalSection[]
  highlightedSections: Set<string>
  modeloTrabalho?: ProposalModelo
  onDownload?: () => void
}

export function ProposalTemplateWa({
  empresa,
  para,
  projeto,
  proposalNumber,
  dataCriacao,
  sections,
  highlightedSections,
  modeloTrabalho,
  onDownload,
}: ProposalTemplateWaProps) {
  const [downloading, setDownloading] = useState(false)

  async function handleDownloadPDF() {
    if (sections.length === 0) {
      toast.error("Nenhum conteúdo disponível para gerar PDF")
      return
    }

    setDownloading(true)

    try {
      // Construir dados estruturados para o template
      const proposalData = buildWaProjectProposalData({
        empresa,
        para,
        projeto,
        modeloTrabalho,
        dataCriacao,
        proposalNumber,
        sections,
      })

      // Gerar o PDF usando o novo gerador
      await generateWaProjectProposalPDF(proposalData)

      toast.success("PDF gerado com sucesso!")
      onDownload?.()
    } catch (error) {
      // Log error for debugging in development only
      if (process.env.NODE_ENV === 'development') {
        console.error("[ProposalTemplateWa] PDF error:", error)
      }
      toast.error("Erro ao gerar o PDF. Tente novamente.")
    } finally {
      setDownloading(false)
    }
  }

  // Se não há seções, mostrar placeholder
  if (sections.length === 0) {
    return (
      <div className="flex h-full flex-col rounded-lg border border-border bg-card shadow-sm">
        <div className="flex items-center justify-between gap-2 border-b border-border px-4 py-3">
          <h2 className="text-sm font-semibold text-foreground">Proposta Comercial - Wa Project</h2>
        </div>
        <div className="flex-1 overflow-y-auto p-4">
          <div className="flex h-full flex-col items-center justify-center rounded-lg border-2 border-dashed border-border p-6 text-center">
            <FileText className="mb-3 h-12 w-12 text-muted-foreground/40" />
            <p className="text-sm font-medium text-muted-foreground">
              A proposta será gerada aqui conforme você fornecer informações ao assistente.
            </p>
            <p className="mt-1 text-xs text-muted-foreground">
              Comece a conversa ao lado!
            </p>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="flex h-full flex-col rounded-lg border border-border bg-card shadow-sm">
      {/* Header */}
      <div className="flex items-center justify-between gap-2 border-b border-border px-4 py-3">
        <h2 className="text-sm font-semibold text-foreground">Proposta Comercial - Wa Project</h2>
        <Button

