"use client"

import { useState } from "react"
import { Download, Loader2, FileText } from "lucide-react"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"
import type { ProposalSection, ProposalModelo } from "@/lib/proposal-types"
import { formatDateShort } from "@/lib/proposal-types"
import { generateWaProjectProposalPDF } from "@/lib/wa-project-pdf-generator"

interface ProposalTemplateWaProps {
  empresa: string
  para?: string
  projeto?: string
  proposalNumber: string
  dataCriacao: number
  sections: ProposalSection[]
  highlightedSections: Set<string>
  modeloTrabalho?: ProposalModelo
  onDownload?: () => void
}

export function ProposalTemplateWa({
  empresa,
  para,
  projeto,
  proposalNumber,
  dataCriacao,
  sections,
  highlightedSections,
  modeloTrabalho,
  onDownload,
}: ProposalTemplateWaProps) {
  const [downloading, setDownloading] = useState(false)

  async function handleDownloadPDF() {
    if (sections.length === 0) {
      toast.error("Nenhum conteúdo disponível para gerar PDF")
      return
    }

    setDownloading(true)

    try {
      // Construir dados estruturados para o template
      const proposalData = buildWaProjectProposalData({
        empresa,
        para,
        projeto,
        modeloTrabalho,
        dataCriacao,
        proposalNumber,
        sections,
      })

      // Gerar o PDF usando o novo gerador
      await generateWaProjectProposalPDF(proposalData)

      toast.success("PDF gerado com sucesso!")
      onDownload?.()
    } catch (error) {
      // Log error for debugging in development only
      if (process.env.NODE_ENV === 'development') {
        console.error("[ProposalTemplateWa] PDF error:", error)
      }
      toast.error("Erro ao gerar o PDF. Tente novamente.")
    } finally {
      setDownloading(false)
    }
  }

  // Se não há seções, mostrar placeholder
  if (sections.length === 0) {
    return (
      <div className="flex h-full flex-col rounded-lg border border-border bg-card shadow-sm">
        <div className="flex items-center justify-between gap-2 border-b border-border px-4 py-3">
          <h2 className="text-sm font-semibold text-foreground">Proposta Comercial - Wa Project</h2>
        </div>
        <div className="flex-1 overflow-y-auto p-4">
          <div className="flex h-full flex-col items-center justify-center rounded-lg border-2 border-dashed border-border p-6 text-center">
            <FileText className="mb-3 h-12 w-12 text-muted-foreground/40" />
            <p className="text-sm font-medium text-muted-foreground">
              A proposta será gerada aqui conforme você fornecer informações ao assistente.
            </p>
            <p className="mt-1 text-xs text-muted-foreground">
              Comece a conversa ao lado!
            </p>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="flex h-full flex-col rounded-lg border border-border bg-card shadow-sm">
      {/* Header */}
      <div className="flex items-center justify-between gap-2 border-b border-border px-4 py-3">
        <h2 className="text-sm font-semibold text-foreground">Proposta Comercial - Wa Project</h2>
        <Button
          variant="outline"
          size="sm"
          onClick={handleDownloadPDF}
          disabled={downloading}
          className="text-wa-brand-primary border-wa-brand-primary/30 hover:bg-wa-brand-accent"
        >
          {downloading ? (
            <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
          ) : (
            <Download className="mr-1.5 h-3.5 w-3.5" />
          )}
          Baixar PDF
        </Button>
      </div>

      {/* Document content */}
      <div className="flex-1 overflow-y-auto p-4 lg:p-6">
        <div className="mx-auto max-w-[700px] rounded-lg border border-border bg-background p-4 shadow-md lg:p-8">
          {/* Capa do documento */}
          <div className="mb-8 text-center">
            {/* Logo espaço reservado */}
            <div className="mb-6 flex justify-center">
              <div className="h-12 w-32 bg-wa-brand-primary rounded flex items-center justify-center">
                <span className="text-wa-brand-foreground font-bold text-lg">Wa Project</span>
              </div>
            </div>

            {/* Título principal */}
            <h1 className="text-2xl font-extrabold text-wa-brand-primary mb-2">
              Proposta Comercial
            </h1>

            {/* Nome do projeto */}
            {projeto && (
              <h2 className="text-xl font-bold text-wa-brand-primary mb-4">
                {projeto}
              </h2>
            )}

            {/* Informações da proposta */}
            <div className="text-sm text-foreground mb-4">
              <p>{formatDateShort(dataCriacao)} | Válido por 30 dias</p>
              <p><strong>Para:</strong> {para || empresa}</p>
              <p><strong>Tipo:</strong> {modeloTrabalho !== "Vazio" ? modeloTrabalho : "Escopo Fechado"}</p>
            </div>

            {/* Linha separadora */}
            <div className="mx-auto h-px w-16 bg-wa-brand-primary/30 mb-6" />
          </div>

          {/* Seções do documento */}
          <div className="space-y-8">
            {sections.map((section) => (
              <div
                key={section.key}
                className={cn(
                  "rounded-md px-3 py-2 transition-colors",
                  highlightedSections.has(section.key) && "section-highlight"
                )}
              >
                <h2 className="mb-3 text-lg font-bold text-wa-brand-primary border-b border-wa-brand-primary/20 pb-2">
                  {section.title}
                </h2>
                <div className="prose prose-sm max-w-none">
                  <WaProjectMarkdownRenderer content={section.content} />
                </div>
              </div>
            ))}
          </div>

          {/* Rodapé do documento */}
          <div className="mt-12 pt-8 border-t border-border text-center">
            <div className="mb-6">
              <p className="text-lg font-bold text-wa-brand-primary mb-2">
                Não é sobre desenvolvimento, é sobre envolvimento.
              </p>
              <p className="text-base font-semibold text-foreground">
                Obrigado por confiar na Wa Project!
              </p>
            </div>

            {/* Informações da empresa */}
            <div className="text-xs text-muted-foreground space-y-1">
              <p><strong>Wa Project Soluções Tecnológicas LTDA.</strong></p>
              <p>CNPJ: 19.317.018/0001-40</p>
              <p>Website: waproject.com.br</p>
              <p>Email: comercial@waproject.com.br</p>
              <p>Telefone/WhatsApp: (11) 5028-2010</p>
            </div>

            <p className="mt-4 text-xs text-muted-foreground">
              Proposta válida por 30 dias a partir da data de emissão
            </p>

            {/* Logo no rodapé */}
            <div className="mt-4 flex justify-center">
              <div className="h-6 w-20 bg-wa-brand-primary rounded flex items-center justify-center">
                <span className="text-wa-brand-foreground font-bold text-xs">Wa Project</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

